/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Responsibilities:
 * 1. Payload formatting — converts NotificationPayload to JSON
 * 2. HTTP delivery — POSTs to the configured webhook URL
 *
 * Implements NotificationAdapter interface. Must not throw — returns failed
 * NotificationResult on errors.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookConfig {
  /** Default webhook URL (used when recipient is not a URL) */
  url?: string;
  /** HTTP headers to include with every request */
  headers?: Record<string, string>;
  /** Request timeout in milliseconds */
  timeoutMs?: number;
}

export const defaultWebhookConfig: WebhookConfig = {
  timeoutMs: 5000,
};

/**
 * A formatted webhook payload ready for delivery.
 */
export interface WebhookPayload {
  url: string;
  method: 'POST';
  headers: Record<string, string>;
  body: string;
}

/**
 * Transport interface for pluggable webhook delivery.
 * Implement this to swap in a real HTTP client.
 */
export interface WebhookTransport {
  post(payload: WebhookPayload): Promise<{ statusCode: number; body?: string }>;
}

/**
 * In-memory transport for development and testing.
 * Stores all sent webhooks for inspection.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: Array<WebhookPayload & { statusCode: number }> = [];

  async post(payload: WebhookPayload): Promise<{ statusCode: number; body?: string }> {
    this.deliveries.push({ ...payload, statusCode: 200 });
    return { statusCode: 200, body: '{"ok":true}' };
  }

  getDeliveries(): Array<WebhookPayload & { statusCode: number }> {
    return [...this.deliveries];
  }

  clear(): void {
    this.deliveries = [];
  }
}

/**
 * Resolves the target webhook URL from the recipient string and config.
 * If the recipient looks like a URL, use it directly. Otherwise fall back to config.url.
 */
function resolveWebhookUrl(recipient: string, config: WebhookConfig): string | undefined {
  if (recipient.startsWith('http://') || recipient.startsWith('https://')) {
    return recipient;
  }
  return config.url;
}

/**
 * Format a NotificationPayload into the JSON body sent to the webhook.
 */
function formatWebhookBody(payload: NotificationPayload): string {
  return JSON.stringify({
    id: payload.id,
    type: payload.type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    priority: payload.priority,
    createdAt: payload.createdAt.toISOString(),
    metadata: payload.metadata ?? {},
  });
}

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private config: WebhookConfig;

  constructor(options?: {
    config?: WebhookConfig;
    transport?: WebhookTransport;
  }) {
    this.config = options?.config ?? defaultWebhookConfig;
    this.transport = options?.transport ?? new InMemoryWebhookTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Step 1: Resolve webhook URL
      const url = resolveWebhookUrl(payload.recipient, this.config);
      if (!url) {
        this.logger.warn(`Cannot resolve webhook URL for recipient: ${payload.recipient}`);
        return {
          notificationId: payload.id,
          channel: 'webhook',
          success: false,
          error: `Cannot resolve webhook URL for recipient: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Step 2: Format payload
      const webhookPayload: WebhookPayload = {
        url,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...this.config.headers,
        },
        body: formatWebhookBody(payload),
      };

      // Step 3: Send via transport
      this.logger.info(`Posting webhook to ${url} for notification ${payload.id}`);
      const result = await this.transport.post(webhookPayload);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.logger.info(`Webhook delivered: ${payload.id} (status: ${result.statusCode})`);
        return {
          notificationId: payload.id,
          channel: 'webhook',
          success: true,
          deliveredAt: new Date(),
        };
      }

      this.logger.warn(`Webhook failed: ${payload.id} (status: ${result.statusCode})`);
      return {
        notificationId: payload.id,
        channel: 'webhook',
        success: false,
        error: `Webhook returned status ${result.statusCode}`,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to post webhook for ${payload.id}: ${message}`);
      return {
        notificationId: payload.id,
        channel: 'webhook',
        success: false,
        error: `Webhook delivery failed: ${message}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get the underlying transport (for testing).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

