        },
      });

      await adapterWithHeaders.send(makePayload());

      const delivery = transport.getDeliveries()[0]!;
      expect(delivery.headers['Authorization']).toBe('Bearer secret-token');
      expect(delivery.headers['X-Custom']).toBe('value');
      expect(delivery.headers['Content-Type']).toBe('application/json');
    });
  });

  describe('URL resolution', () => {
    it('uses recipient as URL when it starts with https://', async () => {
      await adapter.send(makePayload({ recipient: 'https://my-hook.example.com/path' }));
      expect(transport.getDeliveries()[0]!.url).toBe('https://my-hook.example.com/path');
    });

    it('uses recipient as URL when it starts with http://', async () => {
      await adapter.send(makePayload({ recipient: 'http://localhost:3000/hook' }));
      expect(transport.getDeliveries()[0]!.url).toBe('http://localhost:3000/hook');
    });
  });

  describe('InMemoryWebhookTransport', () => {
    it('stores sent webhooks', async () => {
      const t = new InMemoryWebhookTransport();
      const webhookPayload: WebhookPayload = {
        url: 'https://test.example.com/hook',
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: '{"test":true}',
      };

      const result = await t.post(webhookPayload);

      expect(result.statusCode).toBe(200);
      expect(t.getDeliveries()).toHaveLength(1);
      expect(t.getDeliveries()[0]!.url).toBe('https://test.example.com/hook');
    });

    it('clears deliveries', async () => {
      const t = new InMemoryWebhookTransport();
      await t.post({
        url: 'https://test.example.com',
        method: 'POST',
        headers: {},
        body: '{}',
      });

      t.clear();
      expect(t.getDeliveries()).toHaveLength(0);
    });
  });

  describe('defaults', () => {
    it('has default timeout config', () => {
      expect(defaultWebhookConfig.timeoutMs).toBe(5000);
    });
  });
